from flask import Flask, request, jsonify
import face_recognition as fr
import numpy as np

app = Flask(__name__)

# Load the known images and learn how to recognize them
known_faces = [fr.load_image_file("path_to_employee1"), 
               fr.load_image_file("path_to_employee2"), 
               # Add more employees as required
              ]
known_face_encodings = [fr.face_encodings(face)[0] for face in known_faces]
known_face_names = ["Employee1", "Employee2", # Employee names should match the order of faces
                     # Add more employees as required
                   ]

@app.route('/recognize', methods=['POST'])
def recognize():
    if request.files:
        image_file = request.files["image"]
        unknown_face = fr.load_image_file(image_file)
        unknown_encoding = fr.face_encodings(unknown_face)[0]
        
        results = []
        for (known_name, known_encoding) in zip(known_face_names, known_face_encodings):
            # See how far the test image is from the known faces
            distances = fr.face_distance(known_encoding, np.array([unknown_encoding]))
            
            result = {
                "name": known_name,
                "confidence": round((1-distances[0])*100, 2) # Confidence score is 1 - distance
            }
            results.append(result)
        
        return jsonify({"results": results}), 200
    else:
        return "No image provided", 400

if __name__ == '__main__':
    app.run()